//! P2-05: Vigil evening summary and next-day prep.
//!
//! [`EveningSummary`] compiles a user's day from audit log entries, previews
//! tomorrow's calendar events, and surfaces unresolved items from memory.
//! The compiled context is formatted as an LLM prompt; the caller passes it to
//! Chord for generation.
//!
//! ## Design decisions
//!
//! - **LLM generation** ‚Äî per the spec the summary is generated by the LLM
//!   from aggregated data, consistent with the morning briefing approach.
//!   This module builds the context prompt; generation is the caller's
//!   responsibility.
//!
//! - **Graceful degradation** ‚Äî if no activity exists ("quiet day") the prompt
//!   still produces a useful response focusing on tomorrow.
//!
//! - **No hardcoded values** ‚Äî all config comes from [`EveningConfig`] and
//!   caller-supplied data slices.  No IPs, hostnames, or personal data.
//!
//! ## Quick start
//!
//! ```rust,no_run
//! use lumina_core::vigil::evening::{EveningSummary, EveningConfig};
//!
//! let config = EveningConfig::from_env();
//! let summary = EveningSummary::new(config);
//!
//! // Supply data gathered elsewhere (audit log, calendar, memory)
//! let completed_tasks = vec!["Reviewed PR #42".to_string(), "Sent status update".to_string()];
//! let tomorrow_events = vec!["Team standup at 09:00".to_string()];
//! let unresolved     = vec!["Follow up on vendor quote".to_string()];
//!
//! let prompt = summary.compose_prompt(&completed_tasks, &tomorrow_events, &unresolved);
//! // Pass `prompt` to your Chord/LLM call to produce the final text.
//! println!("{}", prompt);
//! ```

use crate::vigil::config::BriefingConfig;

// ‚îÄ‚îÄ EveningConfig ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// Per-user configuration for the evening summary routine.
///
/// ## Environment variables
///
/// | Variable                      | Default         | Description                              |
/// |-------------------------------|-----------------|------------------------------------------|
/// | `VIGIL_EVENING_SCHEDULE`      | `"0 20 * * *"`  | Cron for evening delivery (default 8pm)  |
/// | `VIGIL_EVENING_USER_NAME`     | `""`            | Display name used in the summary prompt  |
/// | `VIGIL_EVENING_TIMEZONE`      | `"UTC"`         | User's timezone (IANA)                   |
/// | `VIGIL_EVENING_LLM_MODEL`     | `"lumina-deep"` | Model alias for generation               |
/// | `VIGIL_EVENING_DELIVER_CHANNEL` | `"matrix"`    | Delivery channel name                    |
/// | `VIGIL_EVENING_ENABLED`       | `"true"`        | Set `"false"` to disable the routine     |
#[derive(Debug, Clone)]
pub struct EveningConfig {
    /// Cron expression controlling when the summary fires (default: 8pm daily).
    pub schedule: String,

    /// The user's display name, injected into the generation prompt.
    pub user_name: String,

    /// IANA timezone name (e.g. `"America/Los_Angeles"`).
    pub timezone: String,

    /// Model alias passed to the Chord request.
    pub llm_model: String,

    /// Delivery channel name (e.g. `"matrix"`).
    pub deliver_channel: String,

    /// Whether the evening summary routine is enabled.
    ///
    /// When `false`, [`make_evening_routine`] returns a routine with
    /// `enabled = false` so the scheduler skips it.
    pub enabled: bool,
}

impl Default for EveningConfig {
    fn default() -> Self {
        Self {
            schedule:        "0 20 * * *".to_string(),
            user_name:       String::new(),
            timezone:        "UTC".to_string(),
            llm_model:       "lumina-deep".to_string(),
            deliver_channel: "matrix".to_string(),
            enabled:         true,
        }
    }
}

impl EveningConfig {
    /// Load configuration from environment variables.
    ///
    /// Missing variables use their defaults; no variable is required.
    pub fn from_env() -> Self {
        use std::env;
        let mut cfg = Self::default();

        if let Ok(v) = env::var("VIGIL_EVENING_SCHEDULE") {
            if !v.is_empty() {
                cfg.schedule = v;
            }
        }
        if let Ok(v) = env::var("VIGIL_EVENING_USER_NAME") {
            cfg.user_name = v; // intentionally allow empty
        }
        if let Ok(v) = env::var("VIGIL_EVENING_TIMEZONE") {
            if !v.is_empty() {
                cfg.timezone = v;
            }
        }
        if let Ok(v) = env::var("VIGIL_EVENING_LLM_MODEL") {
            if !v.is_empty() {
                cfg.llm_model = v;
            }
        }
        if let Ok(v) = env::var("VIGIL_EVENING_DELIVER_CHANNEL") {
            if !v.is_empty() {
                cfg.deliver_channel = v;
            }
        }
        if let Ok(v) = env::var("VIGIL_EVENING_ENABLED") {
            cfg.enabled = !matches!(v.trim().to_lowercase().as_str(), "false" | "0" | "no");
        }

        cfg
    }
}

// ‚îÄ‚îÄ EveningSummary ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// The Vigil evening summary engine.
///
/// Compiles today's completed tasks, tomorrow's calendar preview, and any
/// unresolved items into an LLM prompt that produces a natural evening
/// reflection and next-day prep message.
pub struct EveningSummary {
    config: EveningConfig,
}

impl EveningSummary {
    /// Create a new `EveningSummary` with the given config.
    pub fn new(config: EveningConfig) -> Self {
        Self { config }
    }

    /// Build an `EveningSummary` using morning briefing config conventions for
    /// shared fields (user_name, timezone, llm_model, deliver_channel).
    ///
    /// Evening-specific env vars (`VIGIL_EVENING_SCHEDULE`, `VIGIL_EVENING_ENABLED`)
    /// are still read, so callers get consistent env-var behaviour regardless of
    /// which constructor they use.  This constructor is useful when callers hold a
    /// `BriefingConfig` and want a matching evening config without duplicating
    /// all env-var reads.
    pub fn from_briefing_config(morning: &BriefingConfig) -> Self {
        let evening_schedule = std::env::var("VIGIL_EVENING_SCHEDULE")
            .ok()
            .filter(|s| !s.is_empty())
            .unwrap_or_else(|| "0 20 * * *".to_string());

        let enabled = std::env::var("VIGIL_EVENING_ENABLED")
            .map(|v| !matches!(v.trim().to_lowercase().as_str(), "false" | "0" | "no"))
            .unwrap_or(true);

        let config = EveningConfig {
            schedule:        evening_schedule,
            user_name:       morning.user_name.clone(),
            timezone:        morning.timezone.clone(),
            llm_model:       morning.llm_model.clone(),
            deliver_channel: morning.deliver_channel.clone(),
            enabled,
        };
        Self { config }
    }

    /// Compose the LLM prompt from pre-collected data slices.
    ///
    /// All three slices may be empty ‚Äî the function always returns a non-empty
    /// prompt that gracefully handles the "quiet day" case.
    ///
    /// ## Arguments
    ///
    /// - `completed_tasks` ‚Äî tasks or conversations completed today (from audit log).
    /// - `tomorrow_events` ‚Äî calendar events scheduled for tomorrow.
    /// - `unresolved`      ‚Äî unresolved reminders or action items from memory.
    pub fn compose_prompt(
        &self,
        completed_tasks: &[String],
        tomorrow_events: &[String],
        unresolved: &[String],
    ) -> String {
        let name_clause = if self.config.user_name.is_empty() {
            String::new()
        } else {
            format!(" for {}", self.config.user_name)
        };

        let tz_clause = if self.config.timezone == "UTC" || self.config.timezone.is_empty() {
            String::new()
        } else {
            format!(" (timezone: {})", self.config.timezone)
        };

        // ‚îÄ‚îÄ Today section ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
        let today_section = if completed_tasks.is_empty() {
            "Today was quiet ‚Äî no recorded activity.".to_string()
        } else {
            let items = completed_tasks
                .iter()
                .map(|t| format!("- {}", t))
                .collect::<Vec<_>>()
                .join("\n");
            format!("Completed today:\n{}", items)
        };

        // ‚îÄ‚îÄ Tomorrow section ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
        let tomorrow_section = if tomorrow_events.is_empty() {
            "No calendar events scheduled for tomorrow.".to_string()
        } else {
            let items = tomorrow_events
                .iter()
                .map(|e| format!("- {}", e))
                .collect::<Vec<_>>()
                .join("\n");
            format!("Tomorrow's calendar:\n{}", items)
        };

        // ‚îÄ‚îÄ Unresolved section ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
        let unresolved_section = if unresolved.is_empty() {
            String::new()
        } else {
            let items = unresolved
                .iter()
                .map(|u| format!("- {}", u))
                .collect::<Vec<_>>()
                .join("\n");
            format!("\nUnresolved items:\n{}", items)
        };

        format!(
            "Generate an evening summary{}{} from the data below.\n\
             Be brief, reflective, and helpful. Acknowledge the day's work, \
             preview tomorrow, and surface any unresolved items that need attention.\n\n\
             ---\n\n\
             {}\n\n\
             {}\
             {}",
            name_clause,
            tz_clause,
            today_section,
            tomorrow_section,
            unresolved_section,
        )
    }

    /// Return the cron schedule expression from config.
    pub fn schedule(&self) -> &str {
        &self.config.schedule
    }

    /// Return the model alias for LLM generation.
    pub fn llm_model(&self) -> &str {
        &self.config.llm_model
    }

    /// Return the delivery channel name.
    pub fn deliver_channel(&self) -> &str {
        &self.config.deliver_channel
    }

    /// Return `true` if this summary routine is enabled.
    pub fn is_enabled(&self) -> bool {
        self.config.enabled
    }
}

// ‚îÄ‚îÄ Scheduler routine helper ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

/// Returns `true` if `s` is a valid user ID token (alphanumeric, `-`, `_` only).
fn is_valid_user_id(s: &str) -> bool {
    !s.is_empty() && s.chars().all(|c| c.is_ascii_alphanumeric() || c == '-' || c == '_')
}

/// Build a `Routine` definition for the evening summary that can be registered
/// with the background scheduler.
///
/// ## Arguments
///
/// - `config`  ‚Äî the [`EveningConfig`] controlling schedule, model, channel.
/// - `user_id` ‚Äî optional identifier for the user who owns this routine.
///   Embedded in the routine name and prompt as `user_id:<id>` so the
///   scheduler's `on_routine` callback can dispatch to the correct config.
///   Pass `None` for a single-user deployment.
///
/// ## Returned routine properties
///
/// - `name = "evening_summary"` (or `"evening_summary:{user_id}"`)
/// - `schedule` from `config.schedule` ‚Äî default `"0 20 * * *"` (8pm daily)
/// - `model_override = Some(config.llm_model.clone())`
/// - `channel` mapped from `config.deliver_channel`
/// - `enabled` from `config.enabled`
pub fn make_evening_routine(
    config: &EveningConfig,
    user_id: Option<&str>,
) -> crate::scheduler::Routine {
    use crate::scheduler::routine::RoutineChannel;

    let channel = match config.deliver_channel.as_str() {
        "matrix" => RoutineChannel::Matrix,
        "file"   => RoutineChannel::File,
        _        => RoutineChannel::Stdout,
    };

    // Validate user_id to prevent colon/newline injection into routine name
    // and prompt tokens.
    let safe_uid = user_id.and_then(|uid| if is_valid_user_id(uid) { Some(uid) } else { None });

    let (name, prompt) = match safe_uid {
        Some(uid) => (
            format!("evening_summary:{}", uid),
            format!("Generate and deliver the evening summary. user_id:{}", uid),
        ),
        None => (
            "evening_summary".to_string(),
            "Generate and deliver the evening summary.".to_string(),
        ),
    };

    crate::scheduler::Routine {
        name,
        schedule:       config.schedule.clone(),
        prompt,
        model_override: Some(config.llm_model.clone()),
        channel,
        enabled:        config.enabled,
        last_run:       None,
        next_run:       None,
        trigger:        None,
    }
}

