    #[test]
    fn test_from_briefing_config_inherits_user_name() {
        use crate::vigil::config::BriefingConfig;
        let morning = BriefingConfig {
            user_name: "Alice".to_string(),
            ..Default::default()
        };
        let summary = EveningSummary::from_briefing_config(&morning);
        assert_eq!(summary.config.user_name, "Alice");
    }

    #[test]
    #[serial]
    fn test_from_briefing_config_default_schedule_is_8pm() {
        let _g = ENV_LOCK.lock().unwrap();
        std::env::remove_var("VIGIL_EVENING_SCHEDULE");
        use crate::vigil::config::BriefingConfig;
        let morning = BriefingConfig::default();
        let summary = EveningSummary::from_briefing_config(&morning);
        // Without VIGIL_EVENING_SCHEDULE set, should default to 8pm.
        assert_eq!(summary.config.schedule, "0 20 * * *");
        std::env::remove_var("VIGIL_EVENING_SCHEDULE");
    }

    #[test]
    #[serial]
    fn test_from_briefing_config_respects_enabled_env_var() {
        let _g = ENV_LOCK.lock().unwrap();
        std::env::set_var("VIGIL_EVENING_ENABLED", "false");
        use crate::vigil::config::BriefingConfig;
        let morning = BriefingConfig::default();
        let summary = EveningSummary::from_briefing_config(&morning);
        assert!(!summary.config.enabled,
            "from_briefing_config should honour VIGIL_EVENING_ENABLED=false");
        std::env::remove_var("VIGIL_EVENING_ENABLED");
    }

    // ‚îÄ‚îÄ EveningConfig::from_env ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ

    #[test]
    #[serial]
    fn test_from_env_defaults_when_nothing_set() {
        let _g = ENV_LOCK.lock().unwrap();

        let keys = [
            "VIGIL_EVENING_SCHEDULE", "VIGIL_EVENING_USER_NAME",
            "VIGIL_EVENING_TIMEZONE", "VIGIL_EVENING_LLM_MODEL",
            "VIGIL_EVENING_DELIVER_CHANNEL", "VIGIL_EVENING_ENABLED",
        ];
        for k in &keys { std::env::remove_var(k); }

        let cfg = EveningConfig::from_env();
        assert_eq!(cfg.schedule, "0 20 * * *");
        assert_eq!(cfg.llm_model, "lumina-deep");
        assert_eq!(cfg.timezone, "UTC");
        assert!(cfg.enabled);

        for k in &keys { std::env::remove_var(k); }
    }

    #[test]
    #[serial]
    fn test_from_env_reads_schedule() {
        let _g = ENV_LOCK.lock().unwrap();

        std::env::set_var("VIGIL_EVENING_SCHEDULE", "0 21 * * *");
        let cfg = EveningConfig::from_env();
        assert_eq!(cfg.schedule, "0 21 * * *");
        std::env::remove_var("VIGIL_EVENING_SCHEDULE");
    }

    #[test]
    #[serial]
    fn test_from_env_disabled_flag() {
        let _g = ENV_LOCK.lock().unwrap();

        std::env::set_var("VIGIL_EVENING_ENABLED", "false");
        let cfg = EveningConfig::from_env();
        assert!(!cfg.enabled);
        std::env::remove_var("VIGIL_EVENING_ENABLED");
    }
